SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_mem_m_application_form ON sc_mem_m_application_form CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_application_form() RETURNS trigger AS $BODY$
BEGIN

  if coalesce(NEW.application_form_no::text, '') = '' or NEW.application_form_no = ' ' then
    CALL spa_dberrcol('sc_mem_m_application_form','application_form_no',NEW.application_form_no);
  end if;

  if coalesce(OLD.application_form_no::text, '') = '' and (NEW.application_form_no IS NOT NULL AND NEW.application_form_no::text <> '') then
    -- Insert 
    if pka.auto_entry then 
      NEW.cancel_status := '0';
      NEW.entry_id := pka_com_function.fp_login_id();
      NEW.entry_date := statement_timestamp();
      NEW.branch_id := pka_com_function.fp_login_br();
      NEW.approve_status  := '2'; -- รออนุมัติ
    end if;
  end if;
  if OLD.cancel_status = '0' and NEW.cancel_status = '1' then 
    -- ยกเลิกเอกสาร
    null;
  end if;

  if coalesce(NEW.nationality_code::text, '') = '' or NEW.nationality_code = ' ' then
    NEW.nationality_code := '00';
  end if;

  if coalesce(NEW.doc_place_status::text, '') = '' or NEW.doc_place_status = ' ' or  NEW.doc_place_status = '00' then
    NEW.doc_place_status := '02'; --ที่อยู่ปัจจุบัน
  end if;

  if coalesce(NEW.blood_code::text, '') = '' or NEW.blood_code = ' ' then
    NEW.blood_code := '00';
  end if;

  if coalesce(NEW.drop_loanemer_status::text, '') = '' or NEW.drop_loanemer_status = ' ' then
    NEW.drop_loanemer_status := '0';
  end if;

  if coalesce(NEW.drop_loanspec_status::text, '') = '' or NEW.drop_loanspec_status = ' ' then
    NEW.drop_loanspec_status := '0';
  end if;

  if coalesce(NEW.drop_loannormal_status::text, '') = '' or NEW.drop_loannormal_status = ' ' then
    NEW.drop_loannormal_status := '0';
  end if;

  if coalesce(NEW.drop_collactelral_status::text, '') = '' or NEW.drop_collactelral_status = ' ' then
    NEW.drop_collactelral_status := '0';
  end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
